@startuml
skinparam classAttributeIconSize 0

class "PubSubEvent`1" as PubSubEvent1 <<C>>
class UserPreLoginEvent <<C>>
class LoginArgs <<C>> {
  + LoginArgs(user:IUser, phase:LoginPhase)
}
enum LoginPhase <<E>> {
  Request,
  Response,
  Success,
}
class IUser <<C>>

UserPreLoginEvent -|> PubSubEvent1 : <LoginArgs>

LoginArgs --> LoginPhase : Phase
LoginArgs --> IUser : User
@enduml
